body:
The following index definition automatically indexes all the fields in
the `funding_rounds` array of objects for querying. It also uses the
`storedSource` field to store the `round_code`,
`raised_currency_code`, and `raised_amount` fields on `mongot`.
This allows you to query these stored fields using any operator that
supports queries against these field types and retrieve these stored
fields inside the parent object (`funding_rounds`) as individual
documents. For a sample query that demonstrates this, see the [range](range-ref)
[Embedded Documents Example](range-embedded-documents-eg). To query and
retrieve other fields in the parent object (`funding_rounds`), you
must use the `embeddedDocument` operator.

```go
package main

import (
	"context"
	"fmt"
	"log"

	"go.mongodb.org/mongo-driver/v2/bson"
	"go.mongodb.org/mongo-driver/v2/mongo"
	"go.mongodb.org/mongo-driver/v2/mongo/options"
)

func main() {
	ctx := context.Background()
	uri := "<connection-string>"
	client, err := mongo.Connect(options.Client().
		ApplyURI(uri))
	if err != nil {
		panic(err)
	}

	defer func() {
		if err := client.Disconnect(context.TODO()); err != nil {
			panic(err)
		}
	}()

	coll := client.Database("sample_training").Collection("companies")
	const indexName = "default"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the Atlas Search index for the embeddedDocuments field
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", false},
				{"fields", bson.D{
					{"funding_rounds", bson.D{
						{"type", "embeddedDocuments"},
						{"dynamic", true},
						{"storedSource", bson.D{
							{"include", bson.A{"round_code", "raised_currency_code", "raised_amount"}},
						}},
					}},
				}},
			}},
		},
		Options: opts,
	}

	// Create the index
	searchIndexName, err := coll.SearchIndexes().CreateOne(ctx, searchIndexModel)
	if err != nil {
		log.Fatalf("Failed to create the Atlas Search index: %v", err)
	}

	fmt.Println("Name of index created: " + searchIndexName)
}

